"use client";

import { DotLottieReact } from "@lottiefiles/dotlottie-react";
import { ArrowDownIcon } from "lucide-react";
import { useEffect, useState } from "react";

export function Hero() {
	const [isDark, setIsDark] = useState(false);

	useEffect(() => {
		const root = document.documentElement;
		const check = () => setIsDark(root.classList.contains("dark"));
		check();
		const observer = new MutationObserver(check);
		observer.observe(root, { attributes: true, attributeFilter: ["class"] });
		return () => observer.disconnect();
	}, []);

	const handleScrollDown = () => {
		window.scrollTo({ top: window.innerHeight, behavior: "smooth" });
	};

	return (
		<div className="relative flex min-h-screen items-center overflow-hidden">
			{/* Background decorative circles */}
			<div className="absolute top-1/4 right-[-10%] h-[400px] w-[400px] rounded-full bg-primary/10 blur-[100px]" />
			<div className="absolute bottom-1/4 left-[-10%] h-[300px] w-[300px] rounded-full bg-highlight/10 blur-[80px]" />

			<div className="container relative z-10 pt-24">
				<div className="flex items-start gap-8">
					{/* Left content */}
					<div className="flex-1">
						<div className="flex items-center gap-4">
							<YikeTextLogo />
							<TimeTextLogo />
						</div>

						<p className="mt-8 text-2xl font-medium leading-relaxed text-foreground/80 lg:text-3xl">
							慢下脚步
							<br />
							让心灵照亮前行的路
						</p>

						<button
							type="button"
							onClick={handleScrollDown}
							className="mt-12 animate-bounce text-foreground/40 transition-colors hover:text-foreground/70"
						>
							<ArrowDownIcon className="size-8" />
						</button>

						<div className="mt-8 flex items-center gap-4">
							<span className="text-sm text-foreground/50">相关地址</span>
							<a
								href="https://space.bilibili.com"
								target="_blank"
								rel="noreferrer"
								className="text-foreground/50 transition-colors hover:text-foreground"
							>
								<BilibiliIcon className="size-5" />
							</a>
							<a
								href="https://github.com"
								target="_blank"
								rel="noreferrer"
								className="text-foreground/50 transition-colors hover:text-foreground"
							>
								<GithubIcon className="size-5" />
							</a>
						</div>
					</div>

					{/* Right: Lottie animation */}
					<div className="hidden h-[calc(100vh-4rem)] w-[500px] shrink-0 items-center justify-center lg:flex">
						<DotLottieReact
							key={isDark ? "dark" : "light"}
							src={
								isDark
									? "/animations/Interactive Mage animation.lottie"
									: "/animations/CAT KISS.lottie"
							}
							loop
							autoplay
							className="h-full w-full"
						/>
					</div>
				</div>
			</div>
		</div>
	);
}

